stylesheet:
QMainWindow, QWidget { background: #241315; color: #f1f3f4; }
QLineEdit, QSpinBox, QListWidget, QTextEdit, QMdiArea, QComboBox { background: #321b1f; border: 1px solid #7d5157; selection-background-color: #9f3f4c; }
QPushButton, QToolButton { background: #6b3f48; color: #f6fbff; border: 1px solid #a87880; padding: 6px 10px; font-weight: 600; }
QPushButton:hover, QToolButton:hover { background: #80505a; border-color: #d19aa3; }
QPushButton:pressed, QToolButton:pressed { background: #56323a; }
QDockWidget::title { background: #321b1f; color: #ffd6db; padding: 6px; }
